# renovate.json — configure Renovate Bot for structured upgrade batching
{
  "$schema": "https://docs.renovatebot.com/renovate-schema.json",
  "extends": ["config:base"],
  "packageRules": [
    {
      "matchPackagePatterns": ["openai", "anthropic", "langchain.*", "llama.*"],
      "groupName": "LLM SDK dependencies",
      "schedule": ["before 6am on Monday"],
      "reviewers": ["@platform/security", "@platform/ml-quality"],
      "labels": ["llm-sdk-upgrade", "requires-eval-run"],
      "prBodyNotes": "⚠️ LLM SDK upgrade — eval suite re-run REQUIRED before merge"
    },
    {
      "matchUpdateTypes": ["patch"],
      "matchPackagePatterns": ["*"],
      "excludePackagePatterns": ["openai", "anthropic", "langchain.*", "llama.*"],
      "groupName": "Patch updates (non-LLM)",
      "schedule": ["before 6am on Monday"],
      "automerge": false
    },
    {
      "matchUpdateTypes": ["major"],
      "labels": ["major-upgrade", "requires-architecture-review"],
      "reviewers": ["@platform/architecture", "@platform/security"]
    }
  ],
  "vulnerabilityAlerts": {
    "labels": ["security-upgrade"],
    "schedule": ["at any time"],
    "prPriority": 10
  }
}
